ucs.kql:
let suspectBins = dynamic(["vmnat.exe","applaunch.exe","rdpclip.exe","googleupdate.exe","cookie_exporter.exe","bdreinit.exe","gup.exe","vmwarexferlogs.exe"]);
let badDirs = dynamic([@"\programdata\", @"\users\public\", @"\appdata\roaming\", @"\perflogs\", @"\temp\"]);
let sideloaded =
  DeviceProcessEvents
  | where FileName in~ (suspectBins)
  | where tolower(FolderPath) has_any (badDirs)
  | project DeviceId, DeviceName, ProcTime=Timestamp, ProcessId, FileName, FolderPath, ProcessCommandLine, AccountName, InitiatingProcessFileName, InitiatingProcessFolderPath;
let pairedDll =
  DeviceImageLoadEvents
  | where FileName endswith ".dll"
  | where tolower(FolderPath) has_any (badDirs)
  | where InitiatingProcessFileName in~ (suspectBins)
  | where not(SHA256 in ((DeviceFileCertificateInfo | where IsSigned and IsTrusted | project SHA1)))
  | project DeviceId, DllTime=Timestamp, DllPath=FolderPath, DllName=FileName, InitiatingProcessId=InitiatingProcessId, InitiatingProcessFileName, InitiatingProcessFolderPath;
sideloaded
| join kind=inner pairedDll on DeviceId, $left.ProcessId == $right.InitiatingProcessId
| where abs(datetime_diff('second', DllTime, ProcTime)) < 60
| project ProcTime, DeviceName, AccountName, FileName, FolderPath, ProcessCommandLine, DllName, DllPath

let webProcs = dynamic(["w3wp.exe","httpd.exe","tomcat.exe","tomcat9.exe","java.exe","javaw.exe"]);
let recon = dynamic(["cmd.exe","powershell.exe","whoami.exe","net.exe","net1.exe","systeminfo.exe","tasklist.exe","ipconfig.exe","quser.exe","nltest.exe","arp.exe","ping.exe","rundll32.exe"]);
let webshellChildren =
  DeviceProcessEvents
  | where InitiatingProcessFileName in~ (webProcs)
  | where tolower(InitiatingProcessFolderPath) has_any ("\\inetpub\\","\\wwwroot\\","\\tomcat","\\glassfish","\\exchange server\\","\\frontend\\httpproxy\\")
  | where FileName in~ (recon)
  | project DeviceId, DeviceName, T1=Timestamp, ShellPid=ProcessId, ShellName=FileName, ShellCmd=ProcessCommandLine, AccountName, InitiatingProcessFileName, InitiatingProcessFolderPath;
let lsassDump =
  DeviceProcessEvents
  | where (ProcessCommandLine has_all ("comsvcs.dll","MiniDump"))
      or ProcessCommandLine matches regex @"(?i)lsass.*\.(dmp|bin)"
      or FileName in~ ("procdump.exe","procdump64.exe") and ProcessCommandLine has_any ("-ma lsass","lsass.exe")
      or ProcessCommandLine has "sekurlsa::"
  | project DeviceId, T2=Timestamp, DumpCmd=ProcessCommandLine, DumpProc=FileName, DumpAccount=AccountName;
webshellChildren
| join kind=inner lsassDump on DeviceId
| where datetime_diff('minute', T2, T1) between (0 .. 60)
| project T1, T2, DeviceName, AccountName, InitiatingProcessFileName, InitiatingProcessFolderPath, ShellCmd, DumpProc, DumpCmd
| sort by T1 desc
